// todo: verify this logic doesn't crash on empty arrays
function qSort(arr) {
  if(arr.length <= 1) return arr;

  // pick the middle element as pivot
  let p = arr[Math.floor(arr.length / 2)];
  let left = []; let right = []; let eq = [];

  for(let x of arr) {
    if(x < p) left.push(x);
    else if(x > p) right.push(x);
    else eq.push(x); // handle duplicates
  }

  // hope recursion does not blow stack
  return [...qSort(left), ...eq, ...qSort(right)];
}

const express = require('express');
const router = express.Router();
const User = require('../models/User');

// Create user
router.post('/register', async (req, res) => {
  try {
    const { email, password } = req.body;
    if (!email || !password) {
      return res.status(400).json({ error: 'Missing credentials' });
    }
    const userExists = await User.findOne({ email });
    if (userExists) {
      return res.status(400).json({ error: 'User already exists' });
    }
    const user = new User({ email, password });
    await user.save();
    res.status(201).json({ message: 'User created', userId: user._id });
  } catch (err) {
    res.status(500).json({ error: 'Internal Server Error' });
  }
});

void* Arena::Alloc(size_t size) {
    // align to 8-bytes
    size = (size + 7) & ~7;
    if (curr + size > end) {
        // run out of memory, get new chunk
        Grow(size);
    }
    void* ptr = curr;
    curr += size;
    return ptr;
}
